$data_h = [
    "active" => [
        ["algo" => 313, "uuid" => "c49daa", "name" => "hmac", "type" => "mac", "status" => "active", "title" => "HMAC", "description_md" => "HMAC (Hash-based Message Authentication Code) is a MAC construction defined in RFC 2104 and FIPS 198-1. Combines a cryptographic hash function with a secret key using nested hashing: HMAC(K, m) = H((K XOR opad) || H((K XOR ipad) || m)).\n\nHMAC is the universal MAC primitive and is used in TLS, SSH, JWT, HTTPS, S/MIME, IPsec, WPA2, DNSSEC, and virtually every authenticated protocol. Its security depends on the underlying hash. HMAC-SHA256 is the most deployed variant. HMAC is secure as long as the hash is collision-resistant and pseudorandom.", "mental_model" => "Nested double-hashing with key XOR pads -- universal authenticated-protocol primitive.", "purpose" => ["message authentication", "data integrity", "api authentication", "protocol macs"], "good_for" => ["api keys", "jwt signing", "tls mac", "ssh mac", "webhook signatures"], "avoid_for" => ["password hashing (use argon2id)", "digital signatures needing non-repudiation"], "pros" => ["rfc/fips standardized", "universal", "any hash backend", "well-analyzed", "hardware support"], "cons" => ["key required (not a checksum)", "single message auth -- no non-repudiation"], "difficulty" => 1, "security" => 5, "quantum_impact" => "HMAC-SHA256 ~128-bit post-quantum (Grover on hash halves output security). HMAC-SHA3-256 preferred.", "post_quantum_status" => 4, "example" => ["scenario" => "AWS API request signature", "input" => ["key" => "wJalrXUtnFEMI/K7MDENG/bPxRfiCYEXAMPLEKEY", "message" => "GET\n/\ndate:Mon, 09 Sep 2011 23:36:00 GMT\n"], "output" => ["mac" => "595aa31a5ef2b7b7e54c97d52d97edecff81b5f1af95cc7e3c35f2b0d2d27cf"]], "flow" => ["derive ipad_key = key XOR 0x36 repeated", "derive opad_key = key XOR 0x5c repeated", "inner = H(ipad_key || message)", "mac = H(opad_key || inner)"], "related" => ["hmac-sha256", "hmac-sha512", "poly1305", "siphash"]],
        ["algo" => 314, "uuid" => "e6b235", "name" => "hmac-sha256", "type" => "mac", "status" => "active", "title" => "HMAC-SHA-256", "description_md" => "HMAC-SHA-256 is HMAC instantiated with SHA-256. Produces a 256-bit MAC. Defined in FIPS 198-1 / RFC 4868. The most widely deployed MAC primitive.\n\nHMAC-SHA-256 is the default MAC in TLS 1.2, JWT HS256, AWS Signature v4, TOTP/HOTP (RFC 6238), HKDF, and most modern authenticated protocols. 256-bit output truncatable to 128-bit for shorter tags. At 128-bit quantum security level.", "mental_model" => "The standard production MAC -- default in TLS, JWT, AWS, TOTP.", "purpose" => ["api authentication", "jwt hs256", "tls 1.2 mac", "totp", "hkdf"], "good_for" => ["jwt hs256", "aws sig v4", "totp/hotp", "tls hmac", "hkdf"], "avoid_for" => ["password hashing", "bulk data mac (poly1305 faster)"], "pros" => ["fips/rfc standard", "universal deployment", "256-bit output", "hardware acceleration"], "cons" => ["slower than poly1305 for bulk data", "sha256 sequential (not parallel)"], "difficulty" => 1, "security" => 5, "quantum_impact" => "~128-bit post-quantum (Grover halves hash collision resistance).", "post_quantum_status" => 4, "example" => ["scenario" => "JWT HS256 signing", "input" => ["key" => "your-256-bit-secret", "header_payload" => "eyJhbGciOiJIUzI1NiJ9.eyJzdWIiOiJ1c2VyMTIzIn0"], "output" => ["signature" => "SflKxwRJSMeKKF2QT4fwpMeJf36POk6yJV_adQssw5c"]], "flow" => ["hmac construction", "sha-256 hash function", "256-bit mac output"], "related" => ["hmac", "hmac-sha512", "hmac-sha3-256", "hkdf"]],
        ["algo" => 315, "uuid" => "78b2e5", "name" => "hmac-sha512", "type" => "mac", "status" => "active", "title" => "HMAC-SHA-512", "description_md" => "HMAC-SHA-512 is HMAC instantiated with SHA-512. Produces a 512-bit MAC, typically truncated to 256 or 384 bits. RFC 4868 defines HMAC-SHA-384 and HMAC-SHA-512 for IPsec and TLS.\n\nHMAC-SHA-512 is used in TLS 1.2 cipher suites, SSH, and systems requiring 256-bit post-quantum security margin. Faster than SHA-256 on 64-bit CPUs due to 64-bit word operations. JWT HS512 uses it.", "mental_model" => "512-bit MAC for 256-bit post-quantum margin -- faster than SHA-256 on 64-bit.", "purpose" => ["high security mac", "ipsec mac", "tls high security", "jwt hs512"], "good_for" => ["256-bit quantum security", "64-bit cpu bulk mac", "jwt hs512"], "avoid_for" => ["32-bit embedded (sha256 faster)", "when 256-bit output sufficient"], "pros" => ["512-bit output", "256-bit post-quantum security", "faster on 64-bit than sha256", "fips/rfc standard"], "cons" => ["overkill for most use cases", "slower on 32-bit platforms"], "difficulty" => 1, "security" => 5, "quantum_impact" => "~256-bit post-quantum security from 512-bit output.", "post_quantum_status" => 5, "example" => ["scenario" => "TLS 1.2 MAC with HMAC-SHA-512", "input" => ["key" => "0102030405060708090a0b0c0d0e0f10...", "message" => "TLS record payload"], "output" => ["mac" => "b0ba465637458c6990e5a8c5f61d4af7e576d97ff94b872de76f8050361ee3dba91ca5c11aa25eb4d679275cc5788063a5f19741120c4f2de2adebeb10a298dd"]], "flow" => ["hmac construction", "sha-512 64-bit word operations", "512-bit output (often truncated)"], "related" => ["hmac-sha256", "hmac", "hmac-sha3-256"]],
        ["algo" => 316, "uuid" => "fbc176", "name" => "hmac-sha3-256", "type" => "mac", "status" => "active", "title" => "HMAC-SHA3-256", "description_md" => "HMAC-SHA3-256 is HMAC instantiated with SHA3-256. Provides a post-quantum safe MAC with Keccak's sponge construction. Note: SHA-3 has built-in MAC capability via KMAC, but HMAC-SHA3 is compatible with existing HMAC implementations.\n\nHMAC-SHA3-256 is preferred over HMAC-SHA-256 for new post-quantum designs as SHA-3 has a different security model (sponge vs. Merkle-Damgard). Used in post-quantum TLS profiles and quantum-safe protocol migrations.", "mental_model" => "Post-quantum HMAC using Keccak sponge -- migration target from HMAC-SHA256.", "purpose" => ["post-quantum mac", "pq protocol migration"], "good_for" => ["pq migration", "post-quantum tls", "future-proof mac"], "avoid_for" => ["legacy compatibility (use hmac-sha256)"], "pros" => ["keccak sponge security model", "post-quantum preferred", "same hmac interface"], "cons" => ["slower than hmac-sha256 on non-keccak hardware", "kmac128 preferred for new sha3 designs"], "difficulty" => 1, "security" => 5, "quantum_impact" => "~128-bit post-quantum. Keccak sponge better quantum resistance than Merkle-Damgard.", "post_quantum_status" => 4, "example" => ["scenario" => "Post-quantum API authentication", "input" => ["key" => "pq-safe-key-256bit", "message" => "api-request-body"], "output" => ["mac" => "3d0c2e9a4b7f1e8c..."]], "flow" => ["hmac ipad/opad construction", "sha3-256 keccak sponge", "256-bit output"], "related" => ["hmac-sha256", "kmac128", "kmac128-mac"]],
        ["algo" => 317, "uuid" => "310be3", "name" => "hmac-blake2b", "type" => "mac", "status" => "active", "title" => "HMAC-BLAKE2b", "description_md" => "HMAC-BLAKE2b is HMAC instantiated with BLAKE2b. However, BLAKE2b has native keying support, making BLAKE2b-MAC preferred over the HMAC wrapper. HMAC-BLAKE2b provides compatibility with HMAC interfaces.\n\nBLAKE2b is faster than SHA-256/SHA-512 on software. HMAC-BLAKE2b is used where BLAKE2b hardware acceleration exists but HMAC interface is required. BLAKE2b-MAC (native keyed BLAKE2b) is simpler and equally secure.", "mental_model" => "HMAC over BLAKE2b -- prefer native BLAKE2b-MAC; HMAC wrapper for compatibility only.", "purpose" => ["hmac interface compatibility with blake2b"], "good_for" => ["hmac-interface blake2b mac"], "avoid_for" => ["new designs (use blake2b-mac natively keyed)"], "pros" => ["blake2b speed", "hmac interface compatibility"], "cons" => ["blake2b-mac simpler and preferred", "hmac overhead unnecessary for blake2b"], "difficulty" => 1, "security" => 5, "quantum_impact" => "~256-bit post-quantum (BLAKE2b 512-bit output).", "post_quantum_status" => 5, "example" => ["scenario" => "HMAC-BLAKE2b compatibility layer", "input" => ["key" => "0102030405060708...", "message" => "authenticated message"], "output" => ["mac" => "7c3e9b24f1a85d06..."]], "flow" => ["hmac ipad/opad", "blake2b hash (512-bit)", "512-bit mac output"], "related" => ["blake2b-mac", "hmac-sha512", "hmac"]],
        ["algo" => 318, "uuid" => "241189", "name" => "hmac-blake2s", "type" => "mac", "status" => "active", "title" => "HMAC-BLAKE2s", "description_md" => "HMAC-BLAKE2s is HMAC instantiated with BLAKE2s, the 32-bit optimized BLAKE2 variant. Same compatibility rationale as HMAC-BLAKE2b but for 32-bit/embedded platforms.\n\nBLAKE2s is optimized for 32-bit CPUs and embedded systems. HMAC-BLAKE2s is useful where the HMAC interface is required but BLAKE2s speed is desired. BLAKE2s-MAC (native keying) is preferred for new designs.", "mental_model" => "HMAC over BLAKE2s for 32-bit platforms -- prefer native BLAKE2s-MAC.", "purpose" => ["embedded hmac with blake2s speed"], "good_for" => ["32-bit platform hmac"], "avoid_for" => ["new designs (use blake2s-mac)"], "pros" => ["blake2s 32-bit speed", "hmac interface"], "cons" => ["blake2s-mac natively keyed is simpler"], "difficulty" => 1, "security" => 5, "quantum_impact" => "~128-bit post-quantum (256-bit output).", "post_quantum_status" => 4, "example" => ["scenario" => "32-bit embedded HMAC-BLAKE2s", "input" => ["key" => "embeddedkey16b", "message" => "sensor data packet"], "output" => ["mac" => "4f9e7c3b2a1d..."]], "flow" => ["hmac ipad/opad", "blake2s 32-bit hash", "256-bit output"], "related" => ["blake2s-mac", "hmac-blake2b", "hmac"]],
        ["algo" => 319, "uuid" => "74b249", "name" => "aes-cmac", "type" => "mac", "status" => "active", "title" => "AES-CMAC", "description_md" => "AES-CMAC (Cipher-based MAC) is a MAC algorithm based on AES block cipher, standardized in NIST SP 800-38B and RFC 4493. Produces a 128-bit MAC using AES in CBC mode with a subkey derivation step.\n\nAES-CMAC is used in TLS 1.3 cipher suites, EAP-AES-CMAC (802.1X), NIST CAVP-verified firmware authentication, automotive HSM protocols (SHE), and IKEv2. Preferred over CBC-MAC as it handles variable-length messages securely. Hardware AES acceleration provides excellent performance.", "mental_model" => "AES CBC-based MAC with subkey derivation -- standard for AES-hardware platforms.", "purpose" => ["hardware aes mac", "tls 1.3 mac", "automotive hsm", "iot firmware auth"], "good_for" => ["aes-hardware platforms", "eap-aes-cmac", "ike mac", "automotive she"], "avoid_for" => ["software-only (hmac-sha256 faster in software)", "128-bit nonce limited messages"], "pros" => ["aes hardware acceleration", "nist/rfc standard", "128-bit mac", "variable length input"], "cons" => ["128-bit birthday bound at 2^64 messages", "sequential (not parallelizable)"], "difficulty" => 2, "security" => 5, "quantum_impact" => "AES-128 ~64-bit post-quantum via Grover. AES-256-CMAC preferred for PQ.", "post_quantum_status" => 3, "example" => ["scenario" => "AES-CMAC firmware integrity check", "input" => ["key" => "2b7e151628aed2a6abf7158809cf4f3c", "message" => "6bc1bee22e409f96e93d7e117393172a"], "output" => ["mac" => "070a16b46b4d4144f79bdd9dd04a287c"]], "flow" => ["derive K1, K2 subkeys from AES(0)", "CBC-MAC with padding", "XOR final block with K1 or K2", "AES encrypt to get 128-bit tag"], "related" => ["hmac-sha256", "aes-pmac", "poly1305", "ghash"]],
        ["algo" => 320, "uuid" => "6d6929", "name" => "aes-pmac", "type" => "mac", "status" => "active", "title" => "AES-PMAC", "description_md" => "AES-PMAC (Parallelizable MAC) is a parallelizable AES-based MAC designed by Black and Rogaway. Unlike AES-CMAC which is sequential, PMAC can process blocks in parallel, providing higher throughput on multi-core hardware.\n\nAES-PMAC is used in systems that need throughput-optimized AES MACs. Less standardized than AES-CMAC. Found in some high-throughput authenticated encryption libraries. PMAC+ is an improved variant addressing some PMAC limitations.", "mental_model" => "Parallelizable AES block MAC -- CMAC alternative for multi-core throughput.", "purpose" => ["parallel aes mac"], "good_for" => ["high-throughput aes mac", "multi-core mac"], "avoid_for" => ["standard compliance (use aes-cmac)", "embedded sequential"], "pros" => ["parallelizable", "high throughput", "aes based"], "cons" => ["less standardized than cmac", "patent concerns historically"], "difficulty" => 3, "security" => 5, "quantum_impact" => "AES-128 ~64-bit post-quantum.", "post_quantum_status" => 3, "example" => ["scenario" => "PMAC high-throughput bulk MAC", "input" => ["key" => "0102030405060708090a0b0c0d0e0f10", "message" => "large data block..."], "output" => ["mac" => "7f3b9c2a1e4d..."]], "flow" => ["parallel aes blocks with offset tweak", "XOR all results together", "final AES call for tag"], "related" => ["aes-cmac", "vmac", "poly1305"]],
        ["algo" => 322, "uuid" => "3419fd", "name" => "vmac", "type" => "mac", "status" => "active", "title" => "VMAC", "description_md" => "VMAC (Vector-based MAC) is a fast MAC designed by Krovetz and Wei using polynomial hashing over large Galois fields followed by AES-based PRF. Achieves near-memory-bandwidth MAC speeds on 64-bit hardware.\n\nVMAC is used in high-throughput systems requiring MAC verification speeds near memory bandwidth. Less common than HMAC but deployed in some VPN and network security stacks for bulk data authentication. Defined in RFC (draft-krovetz-vmac).", "mental_model" => "Near-memory-bandwidth MAC via polynomial Galois field hashing + AES PRF.", "purpose" => ["high throughput bulk mac"], "good_for" => ["near-memory-speed bulk mac", "vpn bulk data auth"], "avoid_for" => ["general purpose (hmac-sha256 standard)", "short messages (overhead amortizes poorly)"], "pros" => ["near-memory-bandwidth speed", "64-bit optimized", "aes based"], "cons" => ["less deployed than poly1305/hmac", "complex implementation"], "difficulty" => 3, "security" => 5, "quantum_impact" => "AES dependent; 128-bit key ~64-bit post-quantum.", "post_quantum_status" => 3, "example" => ["scenario" => "VPN bulk packet authentication", "input" => ["key" => "0102030405060708090a0b0c0d0e0f10", "nonce" => "000000000000001", "data" => "bulk network packet"], "output" => ["mac" => "9f3c7b2e1a4d..."]], "flow" => ["polynomial hash over 64-bit words", "galois field multiplication", "aes prf finalization"], "related" => ["poly1305", "umac", "aes-pmac"]],
        ["algo" => 323, "uuid" => "67b36d", "name" => "umac", "type" => "mac", "status" => "active", "title" => "UMAC", "description_md" => "UMAC (Universal MAC) is a fast MAC based on universal hashing defined in RFC 4418. Uses NH hash function and AES PRF. Available in 32, 64, 96, and 128-bit tag sizes.\n\nUMAC achieves very high software performance and is used in some high-speed network authentication systems. Less common today than poly1305 for new designs. Defined in RFC 4418.", "mental_model" => "Universal hashing MAC with AES PRF -- fast software, RFC 4418.", "purpose" => ["high speed software mac"], "good_for" => ["fast mac benchmarks", "rfc 4418 compliance"], "avoid_for" => ["new designs (use poly1305 or hmac-sha256)", "hardware constrained"], "pros" => ["very fast software", "rfc standardized", "multiple output sizes"], "cons" => ["poly1305 simpler and comparable", "aes key scheduling overhead"], "difficulty" => 2, "security" => 5, "quantum_impact" => "AES-based PRF; 128-bit key ~64-bit post-quantum.", "post_quantum_status" => 3, "example" => ["scenario" => "UMAC-64 high speed authentication", "input" => ["key" => "0102030405060708090a0b0c0d0e0f10", "nonce" => "000102030405", "message" => "test message"], "output" => ["mac" => "27e8bab3e5a6"]], "flow" => ["nh hash function", "universal polynomial hash", "aes prf output"], "related" => ["vmac", "poly1305", "hmac"]],
        ["algo" => 324, "uuid" => "f00516", "name" => "poly1305", "type" => "mac", "status" => "active", "title" => "Poly1305", "description_md" => "Poly1305 is a fast one-time MAC designed by Bernstein (2005). Evaluates a polynomial over GF(2^130 - 5). Produces a 128-bit MAC. One-time: requires a unique key per message. Used with ChaCha20 in the ChaCha20-Poly1305 AEAD.\n\nPoly1305 is used in TLS 1.3 (ChaCha20-Poly1305), WireGuard, SSH, Signal, and Noise Protocol Framework. Software performance exceeds HMAC-SHA256 significantly. The unique key requirement is typically satisfied by ChaCha20 keystream for the r,s key pair.", "mental_model" => "Fast GF(2^130-5) polynomial one-time MAC -- TLS 1.3, WireGuard, Signal native MAC.", "purpose" => ["aead mac", "tls 1.3 chacha20 mac", "software bulk mac"], "good_for" => ["chacha20-poly1305 aead", "tls 1.3", "wireguard", "signal", "software mac"], "avoid_for" => ["standalone use (need unique key per msg)", "hardware AES-only platforms (use ghash/aes-gcm)"], "pros" => ["very fast in software", "no aes required", "tls 1.3 standard", "constant-time easy to implement"], "cons" => ["one-time mac (unique key per message required)", "128-bit tag only"], "difficulty" => 2, "security" => 5, "quantum_impact" => "128-bit tag; ~64-bit post-quantum forgery resistance.", "post_quantum_status" => 3, "example" => ["scenario" => "ChaCha20-Poly1305 MAC component", "input" => ["r" => "806d5400e52447c036d555408bed685", "s" => "1c9240a5eb55d38af333888604f6b5f0", "message" => "cryptographic forum research group"], "output" => ["tag" => "a8061dc1305136c6c22b8baf0c0127a9"]], "flow" => ["clamp r to valid range", "evaluate polynomial: t = sum(msg_i * r^i) mod 2^130-5", "add s key", "output low 128 bits"], "related" => ["chacha20-poly1305", "ghash", "siphash"]],
        ["algo" => 325, "uuid" => "d6727c", "name" => "siphash", "type" => "mac", "status" => "active", "title" => "SipHash", "description_md" => "SipHash is a fast, short-input MAC and pseudorandom function designed by Aumasson and Bernstein (2012). Uses ARX operations with a 128-bit key and produces 64 or 128-bit output. Designed specifically to prevent hash-flooding attacks on hash tables.\n\nSipHash is used as the hash table default in Rust, Python (3.4+), Ruby, Perl, Swift, and most modern runtimes to prevent algorithmic complexity attacks. Not a general cryptographic MAC -- designed for internal runtime use with short inputs.", "mental_model" => "ARX hash-table MAC preventing hash-flooding -- default in Rust/Python/Ruby runtimes.", "purpose" => ["hash table keying", "algorithmic complexity attack prevention", "short-input prf"], "good_for" => ["hash table randomization", "short message keyed prf", "dos prevention"], "avoid_for" => ["large data mac (hmac faster)", "cryptographic auth (128-bit output insufficient)", "nonce-based protocols (use poly1305)"], "pros" => ["very fast short inputs", "dos prevention", "arx simple", "widely deployed in runtimes"], "cons" => ["64-bit output (collision risk for crypto)", "not for bulk data", "one-time-use key for crypto"], "difficulty" => 1, "security" => 4, "quantum_impact" => "64-bit output: ~32-bit post-quantum. Use SipHash-2-4-128 for more security.", "post_quantum_status" => 2, "example" => ["scenario" => "Rust HashMap key randomization", "input" => ["key" => "000102030405060708090a0b0c0d0e0f", "input" => "hash map key"], "output" => ["siphash" => "726fdb47dd0e0e31"]], "flow" => ["initialize 4x64-bit v0-v3 from key", "sipround compression (SipRound x c times)", "finalize (SipRound x d times)", "output 64 or 128-bit tag"], "related" => ["siphash-2-4", "poly1305", "hmac"]],
        ["algo" => 326, "uuid" => "ceefd8", "name" => "siphash-2-4", "type" => "mac", "status" => "active", "title" => "SipHash-2-4", "description_md" => "SipHash-2-4 is the recommended SipHash variant with 2 compression rounds and 4 finalization rounds. This is the default in all major language runtimes and the standard recommendation.\n\nSipHash-2-4 with 128-bit output is suitable for short-input keyed PRF tasks. It is the direct default in Rust std, Python 3, and most hash table implementations.", "mental_model" => "The standard SipHash variant (2c+4f) -- default everywhere.", "purpose" => ["hash table default", "short mac"], "good_for" => ["same as siphash"], "avoid_for" => ["large bulk mac"], "pros" => ["standard rounds", "deployed everywhere"], "cons" => ["64-bit tag default"], "difficulty" => 1, "security" => 4, "quantum_impact" => "Same as SipHash.", "post_quantum_status" => 2, "example" => ["scenario" => "Python dict hash randomization", "input" => ["key" => "randombytes16", "msg" => "dict key string"], "output" => ["tag" => "1234567890abcdef"]], "flow" => ["2 sipround compression rounds", "4 sipround finalization rounds", "64-bit output"], "related" => ["siphash", "siphash-4-8"]],
        ["algo" => 327, "uuid" => "56f48a", "name" => "siphash-4-8", "type" => "mac", "status" => "active", "title" => "SipHash-4-8", "description_md" => "SipHash-4-8 is the conservative SipHash variant with 4 compression rounds and 8 finalization rounds. Provides a higher security margin than SipHash-2-4 at ~2x performance cost.\n\nSipHash-4-8 is recommended when higher security margin is needed, such as in security-critical hash table applications or when dealing with adversarial inputs.", "mental_model" => "Conservative SipHash with 2x security margin -- higher cost than SipHash-2-4.", "purpose" => ["conservative hash table keying"], "good_for" => ["security-critical hash tables"], "avoid_for" => ["general use (siphash-2-4 sufficient)"], "pros" => ["higher security margin", "same interface as 2-4"], "cons" => ["~2x slower than siphash-2-4"], "difficulty" => 1, "security" => 5, "quantum_impact" => "Same as SipHash -- higher classical margin.", "post_quantum_status" => 3, "example" => ["scenario" => "Security-critical routing table hash", "input" => ["key" => "randombytes16", "route" => "192.168.0.0/16"], "output" => ["tag" => "fedcba9876543210"]], "flow" => ["4 sipround compression rounds", "8 sipround finalization rounds", "64-bit output"], "related" => ["siphash-2-4", "siphash"]],
        ["algo" => 328, "uuid" => "673956", "name" => "kmac128-mac", "type" => "mac", "status" => "active", "title" => "KMAC128", "description_md" => "KMAC128 (Keccak MAC with 128-bit security) is a MAC and PRF defined in NIST SP 800-185. Based on cSHAKE128 with a built-in key and customization string. Unlike HMAC, no double-hashing is needed.\n\nKMAC128 is the NIST-standard MAC for SHA-3/Keccak based systems. Used in NIST post-quantum signature schemes, CMS (NIST SP 800-185), and quantum-safe protocol profiles. Variable output length. KMAC128 is the preferred MAC for new post-quantum designs.", "mental_model" => "NIST SP 800-185 standard Keccak MAC -- preferred PQ MAC for new SHA-3 systems.", "purpose" => ["pq mac", "nist sha-3 mac", "variable length mac"], "good_for" => ["post-quantum protocol mac", "nist pq signature support mac", "variable output length mac"], "avoid_for" => ["non-sha3 environments (hmac-sha256 simpler)"], "pros" => ["nist sp 800-185 standard", "no double-hashing (efficient)", "variable output", "pq safe"], "cons" => ["sha-3 hardware needed for performance", "less deployed than hmac"], "difficulty" => 2, "security" => 5, "quantum_impact" => "~128-bit post-quantum Keccak security.", "post_quantum_status" => 4, "example" => ["scenario" => "KMAC128 PRF for post-quantum key derivation", "input" => ["key" => "404142434445464748494a4b4c4d4e4f", "data" => "sample data for kmac", "customization" => "My Tagged Application"], "output" => ["mac" => "e5780b0d3ea6f7d3a429c5706aa43a00fadbd7d49628839e3187243f456ee14"]], "flow" => ["cshake128 with key prefix", "single-pass keccak sponge", "variable length output squeeze"], "related" => ["kmac256-mac", "hmac-sha3-256", "cshake128"]],
        ["algo" => 329, "uuid" => "dec4ae", "name" => "kmac256-mac", "type" => "mac", "status" => "active", "title" => "KMAC256", "description_md" => "KMAC256 is the 256-bit security level variant of KMAC, defined in NIST SP 800-185. Based on cSHAKE256. Provides 256-bit post-quantum MAC security.\n\nKMAC256 is used where 256-bit post-quantum security is required, such as TOP SECRET classification systems, long-term key derivation, and high-security PQ protocol profiles.", "mental_model" => "256-bit PQ MAC from Keccak -- NIST SP 800-185, high-security systems.", "purpose" => ["256-bit pq mac"], "good_for" => ["top-secret systems", "long-term keys", "256-bit pq kdf"], "avoid_for" => ["standard security (kmac128 sufficient)"], "pros" => ["256-bit post-quantum", "nist standard", "variable output"], "cons" => ["kmac128 sufficient for most uses"], "difficulty" => 2, "security" => 5, "quantum_impact" => "~256-bit post-quantum.", "post_quantum_status" => 5, "example" => ["scenario" => "KMAC256 high security PRF", "input" => ["key" => "404142434445464748494a4b4c4d4e4f505152535455565758595a5b5c5d5e5f", "data" => "high security data"], "output" => ["mac" => "1755133f1534752aad0748f2c706fb5c784512ca4d8f400f4f4e0e7e1e1e1e1"]], "flow" => ["cshake256 keyed variant", "keccak-1600 sponge", "256-bit or variable output"], "related" => ["kmac128-mac", "hmac-sha3-256", "cshake256"]],
        ["algo" => 330, "uuid" => "c42e36", "name" => "blake2b-mac", "type" => "mac", "status" => "active", "title" => "BLAKE2b-MAC", "description_md" => "BLAKE2b-MAC uses BLAKE2b's native keying parameter to produce a MAC without the HMAC wrapper. BLAKE2b natively supports keyed hashing in a single pass, making it more efficient than HMAC-BLAKE2b.\n\nBLAKE2b-MAC is used in WireGuard, libsodium, Argon2, and many modern cryptography libraries as a fast software MAC. Outperforms HMAC-SHA256 significantly in software. Up to 512-bit output.", "mental_model" => "Native BLAKE2b keyed hashing -- faster than HMAC, single-pass, used in WireGuard/libsodium.", "purpose" => ["fast software mac", "keyed hash"], "good_for" => ["wireguard", "libsodium", "argon2 internal", "fast software mac"], "avoid_for" => ["hardware aes-only platforms", "fips compliance (hmac-sha256 required)"], "pros" => ["single-pass faster than hmac", "up to 512-bit output", "libsodium standard"], "cons" => ["not fips approved", "no hardware acceleration for non-blake2 chips"], "difficulty" => 1, "security" => 5, "quantum_impact" => "~256-bit post-quantum (512-bit output).", "post_quantum_status" => 5, "example" => ["scenario" => "libsodium MAC authentication", "input" => ["key" => "000102030405060708090a0b0c0d0e0f101112131415161718191a1b1c1d1e1f", "message" => "Hello, libsodium!"], "output" => ["mac" => "7b50bb1d8d09f5f8b1f8b5e7c3e4..."]], "flow" => ["blake2b init with key as parameter", "single-pass compression", "output up to 64 bytes"], "related" => ["hmac-blake2b", "blake3-mac", "blake2s-mac"]],
        ["algo" => 331, "uuid" => "55e0b2", "name" => "blake2s-mac", "type" => "mac", "status" => "active", "title" => "BLAKE2s-MAC", "description_md" => "BLAKE2s-MAC uses BLAKE2s's native keying for MAC on 32-bit platforms. Produces up to 256-bit output. Preferred over HMAC-BLAKE2s for new designs.\n\nBLAKE2s-MAC is used in embedded systems, IoT devices, and 32-bit platforms where BLAKE2s provides optimal performance.", "mental_model" => "Native BLAKE2s keyed hashing for 32-bit platforms -- embedded MAC.", "purpose" => ["32-bit embedded mac"], "good_for" => ["iot mac", "32-bit embedded mac"], "avoid_for" => ["64-bit servers (blake2b-mac faster)", "fips compliance"], "pros" => ["blake2s 32-bit optimized", "single-pass", "256-bit output"], "cons" => ["256-bit output (vs 512 for blake2b)"], "difficulty" => 1, "security" => 5, "quantum_impact" => "~128-bit post-quantum (256-bit output).", "post_quantum_status" => 4, "example" => ["scenario" => "IoT sensor MAC authentication", "input" => ["key" => "0102030405060708090a0b0c0d0e0f10", "message" => "sensor reading 3.14"], "output" => ["mac" => "9f3b7c2a1e4d..."]], "flow" => ["blake2s init with key parameter", "32-bit word compression", "256-bit output"], "related" => ["blake2b-mac", "hmac-blake2s", "blake3-mac"]],
        ["algo" => 332, "uuid" => "46c908", "name" => "blake3-mac", "type" => "mac", "status" => "active", "title" => "BLAKE3-MAC", "description_md" => "BLAKE3-MAC uses BLAKE3's keyed_hash mode for MAC computation. BLAKE3 natively supports keyed hashing, PRF, and KDF modes. Produces 256-bit default output (extendable).\n\nBLAKE3-MAC is the fastest general-purpose software MAC, surpassing BLAKE2b on multi-core systems due to Merkle tree parallelism. Used in modern cryptography libraries replacing BLAKE2. Also used as a PRF and KDF.", "mental_model" => "BLAKE3 keyed_hash mode -- fastest software MAC, parallelizable Merkle tree.", "purpose" => ["fast software mac", "keyed prf", "kdf"], "good_for" => ["fastest software mac", "multi-core bulk mac", "modern cryptography library mac"], "avoid_for" => ["fips compliance", "sha3-only environments"], "pros" => ["fastest software mac", "parallelizable", "single api: mac/prf/kdf", "256-bit output extendable"], "cons" => ["newer (less deployed than blake2)", "not fips approved"], "difficulty" => 1, "security" => 5, "quantum_impact" => "~128-bit post-quantum default (256-bit output).", "post_quantum_status" => 4, "example" => ["scenario" => "BLAKE3 keyed_hash for API authentication", "input" => ["key" => "whats the Elvish word for friend", "message" => "request body"], "output" => ["mac" => "965b4b4cbf1ed2b9a3da001e6a4f5c6df19fe7..."]], "flow" => ["blake3 keyed_hash mode", "parallel merkle tree compression", "256-bit output (xof extendable)"], "related" => ["blake2b-mac", "hmac-sha256", "blake3"]],
        ["algo" => 333, "uuid" => "97f09e", "name" => "ascon-mac", "type" => "mac", "status" => "active", "title" => "Ascon-MAC", "description_md" => "Ascon-MAC is the MAC function in the Ascon family, standardized in NIST IR 8454 (2023) as part of the NIST Lightweight Cryptography standard. 128-bit key, 128-bit tag. Based on the Ascon-128 permutation.\n\nAscon-MAC is the standard MAC for lightweight/IoT post-quantum applications. Part of the NIST-selected lightweight crypto standard. Used alongside Ascon-AEAD128 and Ascon-Hash in constrained device protocols.", "mental_model" => "NIST lightweight crypto standard MAC -- post-quantum IoT MAC standard.", "purpose" => ["iot mac", "lightweight pq mac", "nist lwc standard mac"], "good_for" => ["iot nist lwc protocol", "post-quantum lwc mac", "ascon family protocol mac"], "avoid_for" => ["high-throughput (hmac-sha256 or poly1305 faster in software)"], "pros" => ["nist lwc 2023 standard", "post-quantum", "iot hardware efficient", "128-bit key+tag"], "cons" => ["less deployed outside iot", "software slower than hmac/poly1305"], "difficulty" => 2, "security" => 5, "quantum_impact" => "~128-bit post-quantum (Keccak-like sponge security).", "post_quantum_status" => 4, "example" => ["scenario" => "NIST LWC IoT firmware authentication", "input" => ["key" => "000102030405060708090a0b0c0d0e0f", "message" => "000102030405060708090a0b0c0d0e0f"], "output" => ["tag" => "3cd8d2a6e7f1b4c9..."]], "flow" => ["ascon-128 permutation sponge", "absorb key + message", "squeeze 128-bit tag"], "related" => ["ascon-aead128", "ascon-prf", "hmac-sha3-256"]],
        ["algo" => 334, "uuid" => "b3dcf8", "name" => "ascon-prf", "type" => "mac", "status" => "active", "title" => "Ascon-PRF", "description_md" => "Ascon-PRF is the pseudorandom function variant in the Ascon family (NIST IR 8454, 2023). Takes a 128-bit key and arbitrary-length input, produces arbitrary-length output. Used for key derivation and MAC in constrained devices.\n\nAscon-PRF provides an XOF-like interface with keying. It is used for both MAC and KDF purposes in Ascon-based lightweight protocol suites.", "mental_model" => "Ascon XOF with key -- NIST lwc PRF/KDF standard for IoT.", "purpose" => ["iot prf", "lightweight kdf", "nist lwc prf"], "good_for" => ["ascon protocol kdf", "lightweight keyed xof", "iot prf"], "avoid_for" => ["standard protocols (use hkdf)"], "pros" => ["nist lwc standard", "variable output length", "kdf+mac unified"], "cons" => ["iot specific", "less deployed outside ascon stack"], "difficulty" => 2, "security" => 5, "quantum_impact" => "~128-bit post-quantum.", "post_quantum_status" => 4, "example" => ["scenario" => "Ascon-PRF IoT key derivation", "input" => ["key" => "000102030405060708090a0b0c0d0e0f", "input" => "context info for kdf"], "output" => ["prf_output" => "7e3b9c2a1f4d..."]], "flow" => ["ascon-128 permutation", "absorb key + input", "squeeze variable length output"], "related" => ["ascon-mac", "ascon-aead128", "kmac128-mac"]],
        ["algo" => 337, "uuid" => "8f6347", "name" => "ghash", "type" => "mac", "status" => "active", "title" => "GHASH", "description_md" => "GHASH is the authentication component of AES-GCM, a polynomial MAC over GF(2^128). Evaluates a Horner polynomial using a key H = AES_K(0). Produces 128-bit authentication tag.\n\nGHASH is not used standalone -- it is the internal MAC of AES-GCM. Understanding GHASH separately matters for implementation, as incorrect GHASH implementations (e.g., nonce reuse in AES-GCM) lead to catastrophic key recovery. CLMUL/PMULL hardware provides fast GHASH on x86/ARM.", "mental_model" => "GF(2^128) polynomial MAC inside AES-GCM -- not standalone; CLMUL hardware accelerated.", "purpose" => ["aes-gcm authentication component"], "good_for" => ["aes-gcm implementation understanding", "hardware ghash analysis"], "avoid_for" => ["standalone mac (use poly1305 or hmac)", "nonce reuse (catastrophic)"], "pros" => ["clmul/pmull hardware", "part of aes-gcm standard", "128-bit tag"], "cons" => ["nonce reuse breaks ghash key recovery", "not standalone safe", "requires unique nonce"], "difficulty" => 4, "security" => 5, "quantum_impact" => "GF(2^128) polynomial; ~64-bit post-quantum forgery resistance.", "post_quantum_status" => 3, "example" => ["scenario" => "AES-GCM internal GHASH computation", "input" => ["H" => "aes_encrypt(0, key)", "ciphertext" => "encrypted blocks", "aad" => "additional data"], "output" => ["ghash" => "authentication tag component"]], "flow" => ["H = AES_K(0)", "horner polynomial over GF(2^128)", "ghash = product of (c_i XOR prev) * H", "combine with E(counter,0) for AES-GCM tag"], "related" => ["aes-gcm", "poly1305", "aes-cmac"]],
    ],
    "legacy" => [
        ["algo" => 321, "uuid" => "f9a8d9", "name" => "xcbc-mac", "type" => "mac", "status" => "legacy", "title" => "XCBC-MAC", "description_md" => "XCBC-MAC (Extended CBC-MAC) improves upon basic CBC-MAC to handle variable-length messages securely using three subkeys. Standardized in RFC 3566 for use in AES-XCBC-MAC-96 (IPsec).\n\nXCBC-MAC was used in IPsec AH and ESP as AES-XCBC-MAC-96 (RFC 3566). Superseded by AES-CMAC (RFC 4493) which addresses the same variable-length issue more cleanly. Still found in legacy IPsec implementations.", "mental_model" => "IPsec CBC-MAC with 3-subkey variable-length fix -- superseded by AES-CMAC.", "purpose" => ["legacy ipsec mac"], "good_for" => ["legacy ipsec rfc 3566 compatibility"], "avoid_for" => ["new designs (use aes-cmac)"], "pros" => ["rfc 3566 standard", "ipsec compatible"], "cons" => ["superseded by aes-cmac", "3-subkey complexity"], "difficulty" => 3, "security" => 4, "quantum_impact" => "AES-based; 128-bit key ~64-bit post-quantum.", "post_quantum_status" => 3, "example" => ["scenario" => "AES-XCBC-MAC-96 IPsec legacy test", "input" => ["key" => "000102030405060708090a0b0c0d0e0f", "message" => "abc"], "output" => ["mac_96" => "47f51b4564966215b8985c63055ed308"]], "flow" => ["derive 3 subkeys K1, K2, K3", "CBC-MAC for all but last block", "XOR last block with K2 or K3", "AES final block"], "related" => ["aes-cmac", "cbc-mac"]],
        ["algo" => 335, "uuid" => "04a130", "name" => "cbc-mac", "type" => "mac", "status" => "legacy", "title" => "CBC-MAC", "description_md" => "CBC-MAC (Cipher Block Chaining MAC) is a basic block-cipher MAC that chains AES blocks in CBC mode, using the final block as the tag. Only secure for fixed-length messages.\n\nCBC-MAC is insecure for variable-length messages (length extension attack) without additional precautions (see XCBC-MAC or CMAC). Superseded by AES-CMAC. Still found in legacy systems and as an educational example.", "mental_model" => "Basic AES CBC chained MAC -- insecure for variable-length, superseded by CMAC.", "purpose" => ["legacy fixed-length block mac"], "good_for" => ["educational study of mac evolution", "fixed-length legacy systems"], "avoid_for" => ["variable-length messages (length extension)", "new designs (use aes-cmac)"], "pros" => ["simple aes-based", "fixed-length message secure"], "cons" => ["length extension attack", "variable-length insecure", "superseded"], "difficulty" => 2, "security" => 2, "quantum_impact" => "Broken for variable-length; avoid.", "post_quantum_status" => 1, "example" => ["scenario" => "Fixed-length CBC-MAC legacy", "input" => ["key" => "0102030405060708090a0b0c0d0e0f10", "blocks" => "fixed 128-bit message"], "output" => ["mac" => "last cbc block"]], "flow" => ["cbc mode chain", "each block XOR then AES", "final block = tag"], "related" => ["aes-cmac", "xcbc-mac"]],
        ["algo" => 336, "uuid" => "fbdda0", "name" => "des-mac", "type" => "mac", "status" => "legacy", "title" => "DES-MAC", "description_md" => "DES-MAC is CBC-MAC using DES (56-bit key). Used in legacy banking/financial systems under ISO 9807 and ANSI X9.9.\n\nDES-MAC is broken -- DES provides only 56-bit key security (easily brute-forced). Used in legacy ATM/POS systems under ISO 9807. Completely deprecated. All systems should migrate to AES-CMAC or HMAC-SHA256.", "mental_model" => "DES CBC-MAC for legacy banking -- 56-bit key broken, ISO 9807 legacy only.", "purpose" => ["legacy banking mac (iso 9807)"], "good_for" => ["legacy atm/pos system analysis"], "avoid_for" => ["any use (56-bit des broken)"], "pros" => ["iso 9807 standard for legacy banking"], "cons" => ["56-bit des broken", "do not use", "migrate to aes-cmac"], "difficulty" => 2, "security" => 1, "quantum_impact" => "DES 56-bit broken classically; quantum irrelevant.", "post_quantum_status" => 1, "example" => ["scenario" => "ISO 9807 legacy ATM MAC", "input" => ["key" => "0102030405060708 (56-bit)", "data" => "transaction record"], "output" => ["mac" => "des-cbc last block"]], "flow" => ["des cbc chain", "56-bit key", "8-byte tag"], "related" => ["aes-cmac", "des"]],
        ["algo" => 338, "uuid" => "320a71", "name" => "kdf1", "type" => "mac", "status" => "legacy", "title" => "KDF1", "description_md" => "KDF1 is a key derivation function from ISO 18033-2 based on a hash function (typically SHA-1 or SHA-256). Used historically for ECIES key derivation.\n\nKDF1 is a simple counter-mode hash KDF: KDF1(Z, l) = H(Z || counter). Superseded by HKDF (RFC 5869) for new designs. Found in legacy ECIES and some ISO 18033-2 implementations.", "mental_model" => "ISO 18033-2 counter hash KDF -- legacy ECIES KDF, superseded by HKDF.", "purpose" => ["legacy ecies kdf", "iso 18033-2 kdf"], "good_for" => ["iso 18033-2 ecies compatibility"], "avoid_for" => ["new designs (use hkdf)"], "pros" => ["iso 18033-2 standard", "simple counter construction"], "cons" => ["superseded by hkdf", "sha-1 based variants insecure", "no salt/info binding"], "difficulty" => 2, "security" => 3, "quantum_impact" => "Hash dependent; SHA-1 based variants broken.", "post_quantum_status" => 2, "example" => ["scenario" => "ISO 18033-2 ECIES legacy KDF", "input" => ["Z" => "shared secret bytes", "len" => "32"], "output" => ["key_material" => "h(Z || 00000001) || ..."]], "flow" => ["counter = 00000001", "repeat H(Z || counter) until length met", "increment counter"], "related" => ["hkdf", "x963-kdf", "concat-kdf"]],
    ],
    "new" => [
        ["algo" => 339, "uuid" => "9e7d55", "name" => "hmac-sha3-384", "type" => "mac", "status" => "new", "title" => "HMAC-SHA3-384", "description_md" => "HMAC-SHA3-384 is HMAC instantiated with SHA3-384. Provides 192-bit post-quantum MAC security. Less common than HMAC-SHA3-256 but available in SHA-3 libraries.\n\nUsed where intermediate security between 128-bit (HMAC-SHA3-256) and 256-bit (HMAC-SHA3-512) is needed.", "mental_model" => "HMAC-SHA3 at 384-bit output -- intermediate PQ security level.", "purpose" => ["192-bit pq mac"], "good_for" => ["intermediate pq security"], "avoid_for" => ["general use (hmac-sha3-256 or hmac-sha3-512 standard)"], "pros" => ["384-bit output", "pq safe keccak"], "cons" => ["non-standard level", "kmac128/256 preferred for sha3"], "difficulty" => 1, "security" => 5, "quantum_impact" => "~192-bit post-quantum.", "post_quantum_status" => 5, "example" => ["scenario" => "Intermediate PQ MAC", "input" => ["key" => "pq-key-384", "msg" => "data"], "output" => ["mac" => "sha3-384 output"]], "flow" => ["hmac construction", "sha3-384 sponge"], "related" => ["hmac-sha3-256", "hmac-sha3-512", "hmac"]],
        ["algo" => 340, "uuid" => "724cc7", "name" => "hmac-sha3-512", "type" => "mac", "status" => "new", "title" => "HMAC-SHA3-512", "description_md" => "HMAC-SHA3-512 is HMAC instantiated with SHA3-512. Provides 256-bit post-quantum MAC security. Available in SHA-3 compliant libraries for the highest PQ security with HMAC interface.\n\nUsed for long-term security requirements or post-quantum compliance at 256-bit level.", "mental_model" => "HMAC-SHA3-512 -- 256-bit PQ MAC with HMAC interface.", "purpose" => ["256-bit pq mac hmac interface"], "good_for" => ["max pq mac security"], "avoid_for" => ["general use (kmac256 preferred for sha3 native)"], "pros" => ["256-bit post-quantum", "hmac interface compatible"], "cons" => ["kmac256 more efficient for sha3"], "difficulty" => 1, "security" => 5, "quantum_impact" => "~256-bit post-quantum.", "post_quantum_status" => 5, "example" => ["scenario" => "Max PQ HMAC", "input" => ["key" => "pq-key-512", "msg" => "data"], "output" => ["mac" => "sha3-512 output"]], "flow" => ["hmac construction", "sha3-512 sponge"], "related" => ["hmac-sha3-256", "kmac256-mac"]],
        ["algo" => 341, "uuid" => "2bbe5b", "name" => "hmac-md5", "type" => "mac", "status" => "new", "title" => "HMAC-MD5", "description_md" => "HMAC-MD5 uses MD5 as the hash in HMAC. HMAC construction somewhat mitigates MD5's weaknesses, but MD5 collision attacks still pose theoretical risks. Used in legacy systems (RADIUS, CHAP) where it cannot be replaced.\n\nHMAC-MD5 is considered weak for new designs. RFC 6151 documents concerns. Still required for RADIUS authentication (RFC 2865), CHAP, and some legacy VPN protocols. Migrate to HMAC-SHA256 where possible.", "mental_model" => "HMAC over MD5 -- legacy RADIUS/CHAP protocol requirement, avoid for new.", "purpose" => ["legacy radius/chap mac"], "good_for" => ["radius legacy", "chap legacy"], "avoid_for" => ["new designs (rfc 6151 advises against)"], "pros" => ["radius/chap compatibility"], "cons" => ["md5 collision concerns", "rfc 6151 discourages", "migrate to hmac-sha256"], "difficulty" => 1, "security" => 2, "quantum_impact" => "MD5 broken for collision; HMAC-MD5 still preimage resistant but avoid.", "post_quantum_status" => 1, "example" => ["scenario" => "RADIUS legacy HMAC-MD5", "input" => ["key" => "radius-shared-secret", "authenticator" => "request authenticator"], "output" => ["mac" => "md5 based response"]], "flow" => ["hmac ipad/opad", "md5 hash function", "128-bit output"], "related" => ["hmac-sha1", "hmac", "md5"]],
        ["algo" => 342, "uuid" => "957e2d", "name" => "hmac-sha1", "type" => "mac", "status" => "new", "title" => "HMAC-SHA1", "description_md" => "HMAC-SHA1 uses SHA-1 in HMAC. SHA-1 collision attacks don't directly break HMAC-SHA1, but it is deprecated for new designs. Required for TOTP/HOTP (RFC 4226), OAuth 1.0, and some legacy TLS cipher suites.\n\nHMAC-SHA1 remains valid for TOTP (where collision attacks are irrelevant) but new systems should prefer HMAC-SHA256. Technically 160-bit output provides sufficient integrity for many uses.", "mental_model" => "HMAC-SHA1 -- TOTP/OAuth 1.0 legacy, SHA-1 deprecated but HMAC construction valid.", "purpose" => ["totp hotp", "oauth 1.0 legacy", "legacy tls mac"], "good_for" => ["rfc 4226 totp/hotp", "oauth 1.0 compatibility"], "avoid_for" => ["new designs (use hmac-sha256)"], "pros" => ["totp/hotp rfc required", "160-bit output"], "cons" => ["sha-1 deprecated", "migrate to hmac-sha256 where possible"], "difficulty" => 1, "security" => 3, "quantum_impact" => "SHA-1 collision broken; HMAC-SHA1 preimage secure but avoid new.", "post_quantum_status" => 2, "example" => ["scenario" => "TOTP HMAC-SHA1 (RFC 4226)", "input" => ["key" => "12345678901234567890", "counter" => "0"], "output" => ["otp" => "755224"]], "flow" => ["hmac construction", "sha-1 hash", "160-bit output truncated to OTP"], "related" => ["hmac-md5", "hmac-sha256", "totp"]],
        ["algo" => 343, "uuid" => "5cbbf5", "name" => "aes-cmac-prf-128", "type" => "mac", "status" => "new", "title" => "AES-CMAC-PRF-128", "description_md" => "AES-CMAC-PRF-128 is a PRF/KDF variant of AES-CMAC that allows variable-length keys by hashing the key first with AES-CMAC. Defined in RFC 4615 for use in IKEv2 when the key is not exactly 128-bit.\n\nAES-CMAC-PRF-128 solves the fixed 128-bit key requirement of AES-CMAC by deriving a 128-bit working key from any-length input. Used in IKEv2 for EAP-AKA and EAP-SIM key derivation.", "mental_model" => "AES-CMAC with variable-key normalization via key hashing -- IKEv2 EAP-AKA.", "purpose" => ["ikev2 eap-aka kdf", "variable-key aes-cmac"], "good_for" => ["rfc 4615 ikev2 eap-aka"], "avoid_for" => ["new designs (use hkdf or kmac128)"], "pros" => ["rfc 4615 standard", "variable-length key support for aes-cmac"], "cons" => ["ikev2 specific niche", "hkdf simpler for new designs"], "difficulty" => 2, "security" => 5, "quantum_impact" => "AES-128 dependent; ~64-bit post-quantum.", "post_quantum_status" => 3, "example" => ["scenario" => "IKEv2 EAP-AKA PRF key derivation", "input" => ["key" => "variable length key material", "x" => "input data"], "output" => ["prf_output" => "128-bit derived key"]], "flow" => ["if key=16: use directly", "else: K = aes-cmac-0 over key bytes", "prf = aes-cmac-K(x)"], "related" => ["aes-cmac", "hkdf", "kdf-ikev2"]],
        ["algo" => 344, "uuid" => "f30043", "name" => "lightmac", "type" => "mac", "status" => "new", "title" => "LightMAC", "description_md" => "LightMAC is a MAC designed for constrained hardware using a lightweight block cipher. Processes message blocks with explicit block counters prepended to avoid the variable-length issues of CBC-MAC.\n\nLightMAC is a NIST LWC companion MAC design. Can use GIFT-64, SIMON, or other lightweight block ciphers. Used alongside NIST LWC AEAD candidates in constrained IoT hardware.", "mental_model" => "Block-counter lightweight MAC for IoT -- NIST LWC companion design.", "purpose" => ["iot lightweight block mac"], "good_for" => ["nist lwc hardware mac", "gift-64 iot mac"], "avoid_for" => ["production (use ascon-mac or aes-cmac)"], "pros" => ["lightweight block cipher", "counter prepend fixes cbc-mac", "iot hardware"], "cons" => ["limited deployment", "ascon-mac nist standard preferred"], "difficulty" => 2, "security" => 3, "quantum_impact" => "Depends on block cipher key size.", "post_quantum_status" => 2, "example" => ["scenario" => "LightMAC-GIFT64 IoT test", "input" => ["key" => "0102030405060708090a0b0c0d0e0f10", "message" => "sensor data 16 bytes"], "output" => ["mac" => "7f3b9c2a"]], "flow" => ["prepend block counter to each message block", "lightweight cipher (gift-64) each block", "XOR chain to get tag"], "related" => ["aes-cmac", "ascon-mac", "gift-cofb"]],
        ["algo" => 345, "uuid" => "b0a272", "name" => "chaskey", "type" => "mac", "status" => "new", "title" => "Chaskey", "description_md" => "Chaskey is a lightweight MAC designed by Mouha, Mennink, and Dobraunig (2014) for microcontrollers. Uses an ARX permutation with 128-bit key for 8-round or 12-round variants.\n\nChaskey is optimized for 32-bit ARM Cortex-M microcontrollers with no hardware crypto. Used in automotive ECUs, sensor nodes, and embedded controllers requiring software MAC without AES acceleration.", "mental_model" => "ARX 128-bit MAC for ARM Cortex-M -- no AES hardware required, automotive ECU.", "purpose" => ["arm cortex-m embedded mac"], "good_for" => ["automotive ecu mac", "no-aes-hardware iot", "32-bit arm mac"], "avoid_for" => ["production with aes hardware (use aes-cmac)"], "pros" => ["arx no aes required", "128-bit key", "arm efficient", "12-round variant provides good margin"], "cons" => ["limited crypto review vs aes-cmac", "not widely standardized"], "difficulty" => 2, "security" => 4, "quantum_impact" => "128-bit key ~64-bit post-quantum.", "post_quantum_status" => 3, "example" => ["scenario" => "Automotive ECU firmware MAC", "input" => ["key" => "000102030405060708090a0b0c0d0e0f", "message" => "ecu calibration data"], "output" => ["mac" => "9f3b7c2a1e4d..."]], "flow" => ["128-bit state initialization", "arx permutation per block", "finalization with subkey xor"], "related" => ["ascon-mac", "aes-cmac", "lightmac"]],
        ["algo" => 346, "uuid" => "9f0953", "name" => "emac", "type" => "mac", "status" => "new", "title" => "EMAC", "description_md" => "EMAC (Encrypted MAC) is a variant of CBC-MAC that encrypts the final tag with a different key to prevent length extension attacks on basic CBC-MAC. Predecessor to OMAC/CMAC.\n\nEMAC is a historical improvement over raw CBC-MAC. Superseded by CMAC/OMAC which use a single key with subkey derivation. Found in legacy EMV payment card specifications.", "mental_model" => "CBC-MAC with final block re-encryption under K2 -- EMV payment legacy MAC.", "purpose" => ["legacy emv payment mac"], "good_for" => ["emv payment card legacy"], "avoid_for" => ["new designs (use aes-cmac)"], "pros" => ["fixes cbc-mac length extension", "emv payment spec"], "cons" => ["superseded by aes-cmac", "two keys required"], "difficulty" => 2, "security" => 4, "quantum_impact" => "AES-based; 128-bit key ~64-bit post-quantum.", "post_quantum_status" => 3, "example" => ["scenario" => "EMV payment card EMAC", "input" => ["k1" => "enc key", "k2" => "mac key", "data" => "transaction data"], "output" => ["mac" => "enc_k2(cbc_k1_chain)"]], "flow" => ["cbc-mac chain with k1", "encrypt final block with k2 instead of k1"], "related" => ["aes-cmac", "cbc-mac", "omac"]],
        ["algo" => 347, "uuid" => "4a3d3e", "name" => "tmac", "type" => "mac", "status" => "new", "title" => "TMAC", "description_md" => "TMAC (Two-Key MAC) is a variant of CBC-MAC using two subkeys (derived from one key) to handle variable-length messages. Between XCBC-MAC (3 keys) and OMAC/CMAC (derived subkeys) in the CBC-MAC evolution.\n\nTMAC reduces XCBC-MAC's 3-key complexity to 2 subkeys while maintaining variable-length security. Superseded by OMAC/CMAC. Historical interest only.", "mental_model" => "CBC-MAC with 2 subkeys for variable-length -- between XCBC-MAC and CMAC historically.", "purpose" => ["mac evolution study"], "good_for" => ["cbc-mac history", "tmac academic study"], "avoid_for" => ["production (use aes-cmac)"], "pros" => ["2 keys simpler than xcbc-mac 3 keys", "variable-length secure"], "cons" => ["superseded by omac/cmac", "historical only"], "difficulty" => 3, "security" => 4, "quantum_impact" => "AES-based; ~64-bit post-quantum.", "post_quantum_status" => 3, "example" => ["scenario" => "TMAC CBC-MAC evolution study", "input" => ["key" => "0102030405060708090a0b0c0d0e0f10", "msg" => "variable length message"], "output" => ["mac" => "tmac 128-bit output"]], "flow" => ["derive K1, K2 from key", "cbc-mac chain", "XOR final block with K1 or K2"], "related" => ["aes-cmac", "xcbc-mac", "omac"]],
        ["algo" => 348, "uuid" => "f3bf20", "name" => "omac", "type" => "mac", "status" => "new", "title" => "OMAC", "description_md" => "OMAC (One-Key CBC-MAC) is a single-key block cipher MAC that handles variable-length messages. OMAC1 is equivalent to AES-CMAC (NIST SP 800-38B). OMAC2 is a variant.\n\nOMAC1 was standardized as CMAC. OMAC and CMAC are effectively the same algorithm. Understanding OMAC is primarily for academic/historical context -- use AES-CMAC in production.", "mental_model" => "One-key CBC-MAC -- OMAC1 is exactly AES-CMAC; historical name.", "purpose" => ["historical aes-cmac name"], "good_for" => ["understanding cmac origins"], "avoid_for" => ["production (use aes-cmac -- same thing)"], "pros" => ["single key", "variable-length secure", "omac1=cmac standard"], "cons" => ["name confusion (just use cmac)"], "difficulty" => 2, "security" => 5, "quantum_impact" => "Same as AES-CMAC.", "post_quantum_status" => 3, "example" => ["scenario" => "OMAC1 = AES-CMAC test", "input" => ["key" => "2b7e151628aed2a6abf7158809cf4f3c", "message" => "6bc1bee22e409f96e93d7e117393172a"], "output" => ["mac" => "070a16b46b4d4144f79bdd9dd04a287c"]], "flow" => ["same as aes-cmac subkey derivation", "cbc chain with subkey XOR"], "related" => ["aes-cmac", "tmac", "xcbc-mac"]],
    ],
];
